/// <summary>
///
/// </summary>
public void dialog()
{
    Dialog                       dialog;
    ETGIntegrationInvoice                    arAPRef;
    DialogField                  dialogARAPRef;
    DialogField                  dialogTransType;
    ;

    dialog = new dialog("Ctrm Integration order create");
    dialogARAPRef       = dialog.addField(extendedTypeStr(ETGIntegrationInvoice), "Invoice number");
    dialog.run();

    if(!dialogARAPRef.value())
    {
        throw error("Invoice number should be fill");
    }
    else if (dialog.run())
    {
        this.create(dialogARAPRef.value());
    }

}

/// <summary>
///
/// </summary>
/// <param name = "_fromdate"></param>
/// <param name = "_todate"></param>
public void create(ETGIntegrationInvoice _arAPRef)
{
    ETG_ARAP_MSGHEADER headerMsg;
    ETG_ARAP_MSGLINES _MsgLines;
    str jourNum;
    ETG_FailedGJManualCreate failedGJManualCreate = new ETG_FailedGJManualCreate();
    Args args = new Args();
    ttsbegin;
    select forupdate headerMsg where headerMsg.ETGARAPREF == _arAPRef
        && headerMsg.ETGIntegrationsStatus != ETGIntegrationStatus::Processed;
    if(!headerMsg)
    {
        info(strFmt("This Invoice number %1 is not available in status table.", _arAPRef));
    }
    else if(headerMsg.ETGDocuType == "INV" && headerMsg.ETGDOCUMENTCAUSE != "Secondary Cost Invoice")
    {
        jourNum = failedGJManualCreate.postInvoice(headerMsg.ETGARAPREF);
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
        headerMsg.ETGLOG  = "";
        headerMsg.update();
    }
    else if(headerMsg.ETGDocuType == "INV" && headerMsg.ETGDOCUMENTCAUSE == "Secondary Cost Invoice")
    {
        jourNum = failedGJManualCreate.postInvoice_MultiLines(headerMsg.ETGARAPREF);
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
        headerMsg.ETGLOG  = "";
        headerMsg.update();
    }
    else if(headerMsg.ETGDocuType == "VCH")
    {
        jourNum = failedGJManualCreate.PostVCH(headerMsg.ETGARAPREF);
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
        headerMsg.ETGLOG  = "";
        headerMsg.update();
    }
    else if(headerMsg.ETGDocuType == "ARCN" && headerMsg.ETGDOCUMENTCAUSE != "Secondary Cost Invoice")
    {
        jourNum = failedGJManualCreate.PostARCN(headerMsg.ETGARAPREF);
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
        headerMsg.ETGLOG  = "";
        headerMsg.update();
    }
    else if(headerMsg.ETGDocuType == "ARCN" && headerMsg.ETGDOCUMENTCAUSE == "Secondary Cost Invoice")
    {
        jourNum = failedGJManualCreate.PostARCN_MultiLines(headerMsg.ETGARAPREF);
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
        headerMsg.ETGLOG  = "";
        headerMsg.update();
    }
    else if(headerMsg.ETGDocuType == "ARDN" && headerMsg.ETGDOCUMENTCAUSE != "Secondary Cost Invoice")
    {
        jourNum = failedGJManualCreate.PostARDN(headerMsg.ETGARAPREF);
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
        headerMsg.ETGLOG  = "";
        headerMsg.update();
    }
    else if(headerMsg.ETGDocuType == "ARDN" && headerMsg.ETGDOCUMENTCAUSE == "Secondary Cost Invoice")
    {
        jourNum = failedGJManualCreate.PostARDN_MultiLines(headerMsg.ETGARAPREF);
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
        headerMsg.ETGLOG  = "";
        headerMsg.update();
    }
    else if(headerMsg.ETGDocuType == "APCN")
    {
        jourNum = failedGJManualCreate.PostAPCN(headerMsg.ETGARAPREF);
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
        headerMsg.ETGLOG  = "";
        headerMsg.update();
    }
    else if(headerMsg.ETGDocuType == "APDN")
    {
        jourNum = failedGJManualCreate.PostAPDN(headerMsg.ETGARAPREF);
        headerMsg.ETGIntegrationsStatus = ETGIntegrationStatus::Processed;
        headerMsg.ETGLOG  = "";
        headerMsg.update();
    }
    if(!jourNum)
    {
        Info(strFmt("This Invoice %1 has been posted already in D365.", _arAPRef));
    }
    else
    {
        Info(strFmt("Integration journal number %1 is created.", jourNum));
    }

    ttscommit;
}

/// <summary>
///
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETG_GeneralJournalManualCreation JournalManualCreation;

    JournalManualCreation = new ETG_GeneralJournalManualCreation();
    JournalManualCreation.run();
}
